import 'dart:convert';

import 'package:flutter/material.dart';

@immutable
class FractalColorStop {
  final double position; // 0..1
  final int colorArgb; // 0xAARRGGBB

  const FractalColorStop({
    required this.position,
    required this.colorArgb,
  });

  Color get color => Color(colorArgb);

  FractalColorStop copyWith({
    double? position,
    int? colorArgb,
  }) {
    return FractalColorStop(
      position: position ?? this.position,
      colorArgb: colorArgb ?? this.colorArgb,
    );
  }

  Map<String, Object?> toJson() => {
        'p': position,
        'c': colorArgb,
      };

  static FractalColorStop fromJson(Map<String, Object?> json) {
    final p = (json['p'] as num?)?.toDouble() ?? 0.0;
    final c = (json['c'] as num?)?.toInt() ?? 0xFFFFFFFF;
    return FractalColorStop(position: p, colorArgb: c);
  }
}

@immutable
class FractalPalette {
  final String id;
  final String name;
  final List<FractalColorStop> stops;
  final bool isBuiltIn;

  const FractalPalette({
    required this.id,
    required this.name,
    required this.stops,
    this.isBuiltIn = false,
  });

  FractalPalette copyWith({
    String? id,
    String? name,
    List<FractalColorStop>? stops,
    bool? isBuiltIn,
  }) {
    return FractalPalette(
      id: id ?? this.id,
      name: name ?? this.name,
      stops: stops ?? this.stops,
      isBuiltIn: isBuiltIn ?? this.isBuiltIn,
    );
  }

  LinearGradient toLinearGradient() {
    final sorted = [...stops]..sort((a, b) => a.position.compareTo(b.position));
    return LinearGradient(
      colors: sorted.map((s) => s.color).toList(),
      stops: sorted.map((s) => s.position.clamp(0.0, 1.0)).toList(),
    );
  }

  Map<String, Object?> toJson() => {
        'id': id,
        'name': name,
        'stops': stops.map((s) => s.toJson()).toList(),
      };

  static FractalPalette fromJson(Map<String, Object?> json) {
    final id = (json['id'] as String?) ?? '';
    final name = (json['name'] as String?) ?? 'Palette';
    final rawStops = (json['stops'] as List?) ?? const [];
    final stops = rawStops
        .whereType<Map>()
        .map((m) => FractalColorStop.fromJson(m.cast<String, Object?>()))
        .toList();

    return FractalPalette(
      id: id,
      name: name,
      stops: stops,
      isBuiltIn: false,
    );
  }

  String toJsonString({bool pretty = true}) {
    final map = toJson();
    return pretty
        ? const JsonEncoder.withIndent('  ').convert(map)
        : jsonEncode(map);
  }

  static FractalPalette fromJsonString(String input) {
    final decoded = jsonDecode(input);
    if (decoded is! Map) {
      throw const FormatException('Palette JSON must be an object');
    }
    return FractalPalette.fromJson(decoded.cast<String, Object?>());
  }
}

import 'dart:convert';

/// Tracks exploration statistics across sessions.
class ExplorationStats {
  final double totalZoomDistance;
  final int totalTimeSeconds;
  final int screenshotsTaken;
  final Set<String> uniqueFractalsExplored;
  final DateTime? firstExplorationDate;
  final DateTime lastUpdated;

  ExplorationStats({
    this.totalZoomDistance = 0.0,
    this.totalTimeSeconds = 0,
    this.screenshotsTaken = 0,
    Set<String>? uniqueFractalsExplored,
    this.firstExplorationDate,
    DateTime? lastUpdated,
  })  : uniqueFractalsExplored = uniqueFractalsExplored ?? {},
        lastUpdated = lastUpdated ?? DateTime.now();

  ExplorationStats copyWith({
    double? totalZoomDistance,
    int? totalTimeSeconds,
    int? screenshotsTaken,
    Set<String>? uniqueFractalsExplored,
    DateTime? firstExplorationDate,
    DateTime? lastUpdated,
  }) {
    return ExplorationStats(
      totalZoomDistance: totalZoomDistance ?? this.totalZoomDistance,
      totalTimeSeconds: totalTimeSeconds ?? this.totalTimeSeconds,
      screenshotsTaken: screenshotsTaken ?? this.screenshotsTaken,
      uniqueFractalsExplored: uniqueFractalsExplored ?? this.uniqueFractalsExplored,
      firstExplorationDate: firstExplorationDate ?? this.firstExplorationDate,
      lastUpdated: lastUpdated ?? DateTime.now(),
    );
  }

  Map<String, dynamic> toJson() => {
        'totalZoomDistance': totalZoomDistance,
        'totalTimeSeconds': totalTimeSeconds,
        'screenshotsTaken': screenshotsTaken,
        'uniqueFractalsExplored': uniqueFractalsExplored.toList(),
        'firstExplorationDate': firstExplorationDate?.toIso8601String(),
        'lastUpdated': lastUpdated.toIso8601String(),
      };

  factory ExplorationStats.fromJson(Map<String, dynamic> json) {
    return ExplorationStats(
      totalZoomDistance: (json['totalZoomDistance'] as num?)?.toDouble() ?? 0.0,
      totalTimeSeconds: json['totalTimeSeconds'] as int? ?? 0,
      screenshotsTaken: json['screenshotsTaken'] as int? ?? 0,
      uniqueFractalsExplored: (json['uniqueFractalsExplored'] as List<dynamic>?)
              ?.map((e) => e as String)
              .toSet() ??
          {},
      firstExplorationDate: json['firstExplorationDate'] != null
          ? DateTime.tryParse(json['firstExplorationDate'] as String)
          : null,
      lastUpdated: json['lastUpdated'] != null
          ? DateTime.tryParse(json['lastUpdated'] as String) ?? DateTime.now()
          : DateTime.now(),
    );
  }

  String encode() => jsonEncode(toJson());

  static ExplorationStats decode(String source) {
    try {
      return ExplorationStats.fromJson(jsonDecode(source) as Map<String, dynamic>);
    } catch (_) {
      return ExplorationStats();
    }
  }
}

